import { useMemo, useState } from "react";
import jsPDF from "jspdf";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);

    const [resumeFile, setResumeFile] = useState(null);
    const [resumeFileName, setResumeFileName] = useState("");
    const [jdFile, setJdFile] = useState(null);
    const [jdFileName, setJdFileName] = useState("");

    const [loading, setLoading] = useState(false);
    const [uploadMessage, setUploadMessage] = useState("");
    const [jdUploadMessage, setJdUploadMessage] = useState("");
    const [darkMode, setDarkMode] = useState(false);
    const [resumeUploaded, setResumeUploaded] = useState(false);

    const theme = useMemo(() => {
        return darkMode
            ? {
                pageBg: "linear-gradient(135deg, #0f172a, #1e293b)",
                cardBg: "#111827",
                text: "#f9fafb",
                subText: "#cbd5e1",
                border: "#334155",
                inputBg: "#0f172a",
                inputText: "#f9fafb",
                sectionBg: "#1f2937",
                mutedTagBg: "#374151",
                mutedTagText: "#e5e7eb",
                matchedBg: "#14532d",
                matchedText: "#dcfce7",
                missingBg: "#7f1d1d",
                missingText: "#fee2e2",
                infoBg: "#172554",
                infoText: "#dbeafe",
                successBg: "#052e16",
                successText: "#dcfce7",
                warningBg: "#3f2a00",
                warningText: "#fde68a",
                progressBg: "#334155",
                shadow: "0 10px 30px rgba(0,0,0,0.35)"
            }
            : {
                pageBg: "linear-gradient(135deg, #eef2ff, #f8fafc)",
                cardBg: "#ffffff",
                text: "#111827",
                subText: "#475569",
                border: "#dbe4ee",
                inputBg: "#ffffff",
                inputText: "#111827",
                sectionBg: "#f8fafc",
                mutedTagBg: "#e5e7eb",
                mutedTagText: "#374151",
                matchedBg: "#dcfce7",
                matchedText: "#166534",
                missingBg: "#fee2e2",
                missingText: "#991b1b",
                infoBg: "#dbeafe",
                infoText: "#1e3a8a",
                successBg: "#dcfce7",
                successText: "#166534",
                warningBg: "#fef3c7",
                warningText: "#92400e",
                progressBg: "#e5e7eb",
                shadow: "0 10px 30px rgba(15,23,42,0.12)"
            };
    }, [darkMode]);

    const analyzeResume = async () => {
        if (!resumeText.trim()) {
            setAnalysis({
                role: "Unknown",
                score: 0,
                requiredKeywords: [],
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Please upload or paste a resume first."]
            });
            return;
        }

        if (!jobDescription.trim()) {
            setAnalysis(null);
            setUploadMessage("Please paste or upload the job description before analyzing.");
            return;
        }

        setLoading(true);
        setUploadMessage("");

        try {
            const res = await fetch("http://localhost:5000/analyze", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({ resumeText, jobDescription })
            });

            const data = await res.json();
            setAnalysis(data);
        } catch (error) {
            setAnalysis({
                role: "Unknown",
                score: 0,
                requiredKeywords: [],
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Could not connect to backend."]
            });
        } finally {
            setLoading(false);
        }
    };

    const uploadResume = async () => {
        if (!resumeFile) {
            setUploadMessage("Please select a resume PDF first.");
            return;
        }

        setLoading(true);
        setUploadMessage("");
        setAnalysis(null);
        setResumeUploaded(false);

        try {
            const formData = new FormData();
            formData.append("resume", resumeFile);

            const res = await fetch("http://localhost:5000/upload", {
                method: "POST",
                body: formData
            });

            const data = await res.json();

            if (data.extractedText) {
                setResumeText(data.extractedText);
                setResumeUploaded(true);
                setUploadMessage("Resume extracted successfully. Now paste or upload the job description below.");
            } else {
                setUploadMessage(data.message || "Could not extract resume text.");
            }
        } catch (error) {
            setUploadMessage("Error uploading resume PDF.");
        } finally {
            setLoading(false);
        }
    };

    const uploadJd = async () => {
        if (!jdFile) {
            setJdUploadMessage("Please select a JD PDF first.");
            return;
        }

        setLoading(true);
        setJdUploadMessage("");

        try {
            const formData = new FormData();
            formData.append("jdFile", jdFile);

            const res = await fetch("http://localhost:5000/upload-jd", {
                method: "POST",
                body: formData
            });

            const data = await res.json();

            if (data.extractedText) {
                setJobDescription(data.extractedText);
                setJdUploadMessage("Job description extracted successfully. You can now analyze the match.");
            } else {
                setJdUploadMessage(data.message || "Could not extract job description.");
            }
        } catch (error) {
            setJdUploadMessage("Error uploading JD PDF.");
        } finally {
            setLoading(false);
        }
    };

    const getScoreColor = (score) => {
        if (score >= 75) return "#22c55e";
        if (score >= 50) return "#f59e0b";
        return "#ef4444";
    };

    const getScoreMessage = (score) => {
        if (score >= 80) return "Strong alignment with the job description.";
        if (score >= 60) return "Decent match, but there are gaps to improve.";
        if (score >= 40) return "Partial match. Resume needs better alignment.";
        return "Low match. Important skills are missing or not highlighted.";
    };

    const getAiExplanation = () => {
        if (!analysis) return "";

        const matchedCount = analysis.matchedSkills?.length || 0;
        const missingCount = analysis.missingSkills?.length || 0;
        const requiredCount = analysis.requiredKeywords?.length || 0;

        return `Your score is ${analysis.score}/100 because ${matchedCount} out of ${requiredCount} key JD keywords were matched in the resume. ${
            missingCount > 0
                ? `The biggest gaps are: ${analysis.missingSkills.slice(0, 5).join(", ")}.`
                : "There are no major missing keywords detected from the JD."
        }`;
    };

    const downloadReport = () => {
        if (!analysis) return;

        const doc = new jsPDF("p", "mm", "a4");
        const pageWidth = 210;
        const margin = 12;
        const contentWidth = pageWidth - margin * 2;
        let y = 18;

        const ensureSpace = (spaceNeeded = 12) => {
            if (y + spaceNeeded > 285) {
                doc.addPage();
                y = 18;
            }
        };

        const addWrappedText = (text, x = margin, fontSize = 11, color = [17, 24, 39], extraGap = 6) => {
            doc.setFontSize(fontSize);
            doc.setTextColor(...color);
            const lines = doc.splitTextToSize(String(text ?? ""), contentWidth - 6);
            ensureSpace(lines.length * 6 + extraGap);
            doc.text(lines, x, y);
            y += lines.length * 6 + extraGap;
        };

        const drawHeader = () => {
            doc.setFillColor(37, 99, 235);
            doc.roundedRect(margin, y, contentWidth, 16, 3, 3, "F");
            doc.setTextColor(255, 255, 255);
            doc.setFontSize(18);
            doc.text("AI Resume Analyzer Report", margin + 6, y + 10);
            y += 24;
        };

        const drawInfoRow = () => {
            ensureSpace(24);

            doc.setFillColor(239, 246, 255);
            doc.roundedRect(margin, y, (contentWidth / 2) - 4, 18, 3, 3, "F");
            doc.setFillColor(245, 243, 255);
            doc.roundedRect(margin + (contentWidth / 2) + 4, y, (contentWidth / 2) - 4, 18, 3, 3, "F");

            doc.setTextColor(30, 58, 138);
            doc.setFontSize(10);
            doc.text("Detected Role", margin + 6, y + 6);
            doc.setFontSize(13);
            doc.text(analysis.role || "Unknown", margin + 6, y + 13);

            doc.setTextColor(91, 33, 182);
            doc.setFontSize(10);
            doc.text("Match Score", margin + (contentWidth / 2) + 10, y + 6);
            doc.setFontSize(13);
            doc.text(`${analysis.score}/100`, margin + (contentWidth / 2) + 10, y + 13);

            y += 26;
        };

        const drawScoreBar = () => {
            ensureSpace(20);

            doc.setTextColor(17, 24, 39);
            doc.setFontSize(12);
            doc.text("Overall Match Score", margin, y);

            y += 6;
            doc.setFillColor(229, 231, 235);
            doc.roundedRect(margin, y, contentWidth, 8, 4, 4, "F");

            const barColor =
                analysis.score >= 75 ? [34, 197, 94] :
                    analysis.score >= 50 ? [245, 158, 11] :
                        [239, 68, 68];

            doc.setFillColor(...barColor);
            doc.roundedRect(margin, y, (contentWidth * analysis.score) / 100, 8, 4, 4, "F");

            y += 14;
        };

        const drawSection = (title, items, fillColor, textColor, emptyText = "None") => {
            const list = items && items.length ? items : [emptyText];
            const estimatedHeight = 14 + list.length * 8 + 8;
            ensureSpace(estimatedHeight);

            doc.setFillColor(...fillColor);
            doc.roundedRect(margin, y, contentWidth, 12, 3, 3, "F");
            doc.setTextColor(255, 255, 255);
            doc.setFontSize(12);
            doc.text(title, margin + 5, y + 8);
            y += 16;

            list.forEach((item) => {
                addWrappedText(`• ${item}`, margin + 2, 11, textColor, 4);
            });

            y += 2;
        };

        drawHeader();
        drawInfoRow();
        drawScoreBar();

        drawSection(
            "Required Skills",
            analysis.requiredKeywords,
            [71, 85, 105],
            [17, 24, 39]
        );

        drawSection(
            "Matched Skills",
            analysis.matchedSkills,
            [22, 163, 74],
            [22, 101, 52]
        );

        drawSection(
            "Missing Skills",
            analysis.missingSkills,
            [220, 38, 38],
            [127, 29, 29]
        );

        drawSection(
            "Suggestions",
            analysis.suggestions,
            [124, 58, 237],
            [76, 29, 149]
        );

        ensureSpace(26);
        doc.setFillColor(219, 234, 254);
        doc.roundedRect(margin, y, contentWidth, 12, 3, 3, "F");
        doc.setTextColor(30, 58, 138);
        doc.setFontSize(12);
        doc.text("AI Explanation", margin + 5, y + 8);
        y += 16;

        addWrappedText(getAiExplanation(), margin + 2, 11, [51, 65, 85], 4);

        doc.save("resume-analysis.pdf");
    };

    const tagStyle = (bg, color) => ({
        display: "inline-block",
        padding: "8px 12px",
        borderRadius: "999px",
        margin: "6px",
        fontSize: "14px",
        fontWeight: "600",
        background: bg,
        color: color,
        border: "1px solid transparent",
        transition: "all 0.2s ease"
    });

    const buttonBase = {
        border: "none",
        borderRadius: "10px",
        padding: "12px 18px",
        cursor: "pointer",
        fontSize: "15px",
        fontWeight: "600",
        transition: "all 0.2s ease"
    };

    const canAnalyze = resumeText.trim() && jobDescription.trim() && !loading;

    return (
        <div
            style={{
                minHeight: "100vh",
                background: theme.pageBg,
                padding: "28px",
                fontFamily: "Inter, Arial, sans-serif",
                color: theme.text
            }}
        >
            <div
                style={{
                    maxWidth: "980px",
                    margin: "0 auto",
                    background: theme.cardBg,
                    borderRadius: "20px",
                    boxShadow: theme.shadow,
                    padding: "28px",
                    border: `1px solid ${theme.border}`
                }}
            >
                <div
                    style={{
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "center",
                        gap: "16px",
                        flexWrap: "wrap",
                        marginBottom: "12px"
                    }}
                >
                    <div>
                        <h1 style={{ margin: 0, fontSize: "32px" }}>AI Resume Analyzer 🚀</h1>
                        <p style={{ marginTop: "8px", color: theme.subText }}>
                            Upload a PDF or paste your resume, then compare it against any job description.
                        </p>
                    </div>

                    <button
                        onClick={() => setDarkMode((prev) => !prev)}
                        style={{
                            ...buttonBase,
                            background: darkMode ? "#f8fafc" : "#0f172a",
                            color: darkMode ? "#0f172a" : "#f8fafc"
                        }}
                    >
                        {darkMode ? "☀ Light Mode" : "🌙 Dark Mode"}
                    </button>
                </div>

                <div
                    style={{
                        background: theme.sectionBg,
                        borderRadius: "16px",
                        padding: "18px",
                        marginTop: "18px",
                        border: `1px solid ${theme.border}`
                    }}
                >
                    <h3 style={{ marginTop: 0 }}>Step 1: Upload Resume (PDF)</h3>
                    <div style={{ display: "flex", gap: "12px", flexWrap: "wrap", alignItems: "center" }}>
                        <input
                            type="file"
                            accept=".pdf"
                            onChange={(e) => {
                                setResumeFile(e.target.files[0]);
                                setResumeFileName(e.target.files[0]?.name || "");
                            }}
                            style={{ color: theme.text }}
                        />

                        <button
                            onClick={uploadResume}
                            style={{
                                ...buttonBase,
                                background: "#16a34a",
                                color: "#ffffff"
                            }}
                        >
                            {loading ? "Uploading..." : "Upload & Extract"}
                        </button>
                    </div>

                    {resumeFileName && (
                        <p style={{ marginTop: "10px", color: theme.subText }}>
                            Selected file: <strong>{resumeFileName}</strong>
                        </p>
                    )}

                    {uploadMessage && (
                        <div
                            style={{
                                marginTop: "12px",
                                background: theme.successBg,
                                color: theme.successText,
                                borderRadius: "10px",
                                padding: "12px 14px"
                            }}
                        >
                            {uploadMessage}
                        </div>
                    )}
                </div>

                <div
                    style={{
                        display: "grid",
                        gridTemplateColumns: "1fr",
                        gap: "18px",
                        marginTop: "18px"
                    }}
                >
                    <div
                        style={{
                            background: theme.sectionBg,
                            borderRadius: "16px",
                            padding: "18px",
                            border: `1px solid ${theme.border}`
                        }}
                    >
                        <h3 style={{ marginTop: 0 }}>Resume</h3>
                        <textarea
                            value={resumeText}
                            onChange={(e) => setResumeText(e.target.value)}
                            placeholder="Resume text will appear here after upload, or paste it manually..."
                            style={{
                                width: "100%",
                                minHeight: "160px",
                                resize: "vertical",
                                borderRadius: "12px",
                                border: `1px solid ${theme.border}`,
                                padding: "14px",
                                fontSize: "14px",
                                lineHeight: 1.5,
                                background: theme.inputBg,
                                color: theme.inputText,
                                outline: "none",
                                boxSizing: "border-box"
                            }}
                        />
                    </div>

                    {(resumeUploaded || resumeText.trim()) && (
                        <div
                            style={{
                                background: theme.warningBg,
                                color: theme.warningText,
                                borderRadius: "12px",
                                padding: "14px",
                                border: `1px solid ${theme.border}`
                            }}
                        >
                            <strong>Step 2:</strong> Paste the job description or upload a JD PDF below, then click <strong>Analyze Match</strong>.
                        </div>
                    )}

                    <div
                        style={{
                            background: theme.sectionBg,
                            borderRadius: "16px",
                            padding: "18px",
                            border: `1px solid ${theme.border}`
                        }}
                    >
                        <h3 style={{ marginTop: 0 }}>Step 2: Upload Job Description (PDF)</h3>
                        <div style={{ display: "flex", gap: "12px", flexWrap: "wrap", alignItems: "center" }}>
                            <input
                                type="file"
                                accept=".pdf"
                                onChange={(e) => {
                                    setJdFile(e.target.files[0]);
                                    setJdFileName(e.target.files[0]?.name || "");
                                }}
                                style={{ color: theme.text }}
                            />

                            <button
                                onClick={uploadJd}
                                style={{
                                    ...buttonBase,
                                    background: "#0ea5e9",
                                    color: "#ffffff"
                                }}
                            >
                                {loading ? "Uploading..." : "Upload JD PDF"}
                            </button>
                        </div>

                        {jdFileName && (
                            <p style={{ marginTop: "10px", color: theme.subText }}>
                                Selected JD file: <strong>{jdFileName}</strong>
                            </p>
                        )}

                        {jdUploadMessage && (
                            <div
                                style={{
                                    marginTop: "12px",
                                    background: theme.successBg,
                                    color: theme.successText,
                                    borderRadius: "10px",
                                    padding: "12px 14px"
                                }}
                            >
                                {jdUploadMessage}
                            </div>
                        )}
                    </div>

                    <div
                        style={{
                            background: theme.sectionBg,
                            borderRadius: "16px",
                            padding: "18px",
                            border: `1px solid ${theme.border}`
                        }}
                    >
                        <h3 style={{ marginTop: 0 }}>Step 3: Job Description</h3>
                        <textarea
                            value={jobDescription}
                            onChange={(e) => setJobDescription(e.target.value)}
                            placeholder="Paste job description here, or upload a JD PDF above..."
                            style={{
                                width: "100%",
                                minHeight: "160px",
                                resize: "vertical",
                                borderRadius: "12px",
                                border: `1px solid ${theme.border}`,
                                padding: "14px",
                                fontSize: "14px",
                                lineHeight: 1.5,
                                background: theme.inputBg,
                                color: theme.inputText,
                                outline: "none",
                                boxSizing: "border-box"
                            }}
                        />
                    </div>
                </div>

                <div
                    style={{
                        display: "flex",
                        gap: "12px",
                        flexWrap: "wrap",
                        justifyContent: "center",
                        marginTop: "18px"
                    }}
                >
                    <button
                        onClick={analyzeResume}
                        disabled={!canAnalyze}
                        style={{
                            ...buttonBase,
                            background: canAnalyze ? "#2563eb" : "#94a3b8",
                            color: "#ffffff",
                            minWidth: "160px",
                            cursor: canAnalyze ? "pointer" : "not-allowed"
                        }}
                    >
                        {loading ? "Analyzing..." : "Analyze Match"}
                    </button>

                    <button
                        onClick={downloadReport}
                        disabled={!analysis}
                        style={{
                            ...buttonBase,
                            background: analysis ? "#7c3aed" : "#94a3b8",
                            color: "#ffffff",
                            minWidth: "170px",
                            cursor: analysis ? "pointer" : "not-allowed"
                        }}
                    >
                        Download Premium PDF
                    </button>
                </div>

                {analysis && (
                    <div style={{ marginTop: "24px" }}>
                        <div
                            style={{
                                display: "grid",
                                gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
                                gap: "16px",
                                marginBottom: "16px"
                            }}
                        >
                            <InfoCard title="Detected Role" value={analysis.role || "Unknown"} theme={theme} />
                            <InfoCard title="Match Quality" value={getScoreMessage(analysis.score)} theme={theme} />
                        </div>

                        <div
                            style={{
                                background: theme.infoBg,
                                color: theme.infoText,
                                borderRadius: "16px",
                                padding: "18px",
                                marginBottom: "16px"
                            }}
                        >
                            <h3 style={{ marginTop: 0 }}>Score: {analysis.score}/100</h3>
                            <div
                                style={{
                                    height: "18px",
                                    background: theme.progressBg,
                                    borderRadius: "999px",
                                    overflow: "hidden",
                                    marginTop: "10px"
                                }}
                            >
                                <div
                                    style={{
                                        width: `${analysis.score}%`,
                                        height: "100%",
                                        background: getScoreColor(analysis.score),
                                        transition: "width 0.8s ease"
                                    }}
                                />
                            </div>
                        </div>

                        <Section title="Required Keywords from JD" theme={theme}>
                            {analysis.requiredKeywords?.length > 0 ? (
                                analysis.requiredKeywords.map((item, index) => (
                                    <span key={index} style={tagStyle(theme.mutedTagBg, theme.mutedTagText)}>
                    {item}
                  </span>
                                ))
                            ) : (
                                <EmptyText text="No job-description keywords extracted." theme={theme} />
                            )}
                        </Section>

                        <Section title="Matched Skills" theme={theme}>
                            {analysis.matchedSkills?.length > 0 ? (
                                analysis.matchedSkills.map((item, index) => (
                                    <span key={index} style={tagStyle(theme.matchedBg, theme.matchedText)}>
                    {item}
                  </span>
                                ))
                            ) : (
                                <EmptyText text="No matched skills found." theme={theme} />
                            )}
                        </Section>

                        <Section title="Missing Skills" theme={theme}>
                            {analysis.missingSkills?.length > 0 ? (
                                analysis.missingSkills.map((item, index) => (
                                    <span key={index} style={tagStyle(theme.missingBg, theme.missingText)}>
                    {item}
                  </span>
                                ))
                            ) : (
                                <EmptyText text="No missing skills." theme={theme} />
                            )}
                        </Section>

                        <Section title="AI Explanation" theme={theme}>
                            <p style={{ margin: 0, color: theme.subText, lineHeight: 1.6 }}>
                                {getAiExplanation()}
                            </p>
                        </Section>

                        <Section title="Suggestions" theme={theme}>
                            {analysis.suggestions?.length > 0 ? (
                                <ul style={{ margin: 0, paddingLeft: "20px", color: theme.subText, lineHeight: 1.8 }}>
                                    {analysis.suggestions.map((item, index) => (
                                        <li key={index}>{item}</li>
                                    ))}
                                </ul>
                            ) : (
                                <EmptyText text="No suggestions." theme={theme} />
                            )}
                        </Section>
                    </div>
                )}
            </div>
        </div>
    );
}

function InfoCard({ title, value, theme }) {
    return (
        <div
            style={{
                background: theme.sectionBg,
                border: `1px solid ${theme.border}`,
                borderRadius: "16px",
                padding: "18px"
            }}
        >
            <p style={{ margin: 0, fontSize: "13px", color: theme.subText }}>{title}</p>
            <h3 style={{ margin: "8px 0 0 0" }}>{value}</h3>
        </div>
    );
}

function Section({ title, children, theme }) {
    return (
        <div
            style={{
                background: theme.sectionBg,
                border: `1px solid ${theme.border}`,
                borderRadius: "16px",
                padding: "18px",
                marginBottom: "16px"
            }}
        >
            <h3 style={{ marginTop: 0 }}>{title}</h3>
            <div style={{ display: "flex", flexWrap: "wrap", alignItems: "flex-start" }}>
                {children}
            </div>
        </div>
    );
}

function EmptyText({ text, theme }) {
    return <p style={{ margin: 0, color: theme.subText }}>{text}</p>;
}

export default App;
